changeSet.sql:
ALTER TABLE producto ADD COLUMN IF NOT EXISTS categoria_id BIGINT;
ALTER TABLE producto ADD CONSTRAINT fk_producto_categoria
    FOREIGN KEY (categoria_id) REFERENCES categoria_producto(id) ON DELETE SET NULL;

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Laptops y Computadores', 'Laptops, PCs y accesorios de cómputo', '💻'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Laptops y Computadores');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Smartphones', 'Teléfonos inteligentes y accesorios', '📱'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Smartphones');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Audio', 'Auriculares, bocinas y equipos de sonido', '🎧'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Audio');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Monitores y TV', 'Pantallas, monitores y televisores', '🖥️'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Monitores y TV');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Periféricos', 'Teclados, mouse y accesorios', '⌨️'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Periféricos');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Almacenamiento', 'Discos duros, SSD y memorias', '💾'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Almacenamiento');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Redes', 'Routers, switches y accesorios de red', '📡'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Redes');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Gaming', 'Consolas, juegos y accesorios gamer', '🎮'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Gaming');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Fotografía y Video', 'Cámaras, drones y accesorios', '📷'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Fotografía y Video');

INSERT INTO categoria_producto (nombre, descripcion, icono)
SELECT 'Accesorios', 'Cables, cargadores y otros accesorios', '🔌'
WHERE NOT EXISTS (SELECT 1 FROM categoria_producto WHERE nombre = 'Accesorios');

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Laptops y Computadores')
WHERE nombre ILIKE '%laptop%' AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Smartphones')
WHERE (nombre ILIKE '%iphone%' OR nombre ILIKE '%samsung%' OR nombre ILIKE '%smartphone%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Audio')
WHERE (nombre ILIKE '%auricular%' OR nombre ILIKE '%bocina%' OR nombre ILIKE '%microfono%' OR nombre ILIKE '%jbl%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Monitores y TV')
WHERE (nombre ILIKE '%monitor%' OR nombre ILIKE '%proyector%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Periféricos')
WHERE (nombre ILIKE '%teclado%' OR nombre ILIKE '%mouse%' OR nombre ILIKE '%webcam%' OR nombre ILIKE '%silla%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Almacenamiento')
WHERE (nombre ILIKE '%ssd%' OR nombre ILIKE '%disco%' OR nombre ILIKE '%memoria%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Redes')
WHERE (nombre ILIKE '%router%' OR nombre ILIKE '%wifi%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Gaming')
WHERE (nombre ILIKE '%playstation%' OR nombre ILIKE '%consola%' OR nombre ILIKE '%gamer%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Fotografía y Video')
WHERE (nombre ILIKE '%camara%' OR nombre ILIKE '%drone%') AND categoria_id IS NULL;

UPDATE producto SET categoria_id = (SELECT id FROM categoria_producto WHERE nombre = 'Accesorios')
WHERE (nombre ILIKE '%hub%' OR nombre ILIKE '%cargador%' OR nombre ILIKE '%cable%') AND categoria_id IS NULL;
